import React, {Component} from 'react';
//eslint-disable-next-line
import '!style-loader!css-loader!react-rangeslider/lib/index.css';
import style from './FilterSlider.css';
import FontAwesome  from 'react-fontawesome';
import Slider from 'react-rangeslider'

class FilterSlider extends Component {

  constructor(props) {
    super(props);

    this.state = {
      value: 0
    };
  }

  fireOnChangeComplete = (ff) => {
    this.props.onChangeComplete(this.state.value)
  }

  componentWillReceiveProps(next) {
    // Sets the default value
    if(next.value) this.setState({value: next.value});
  }

  render() {
    
    const {icon, label, min, max} = this.props;
    const horizontalLabels = {
      [min]: min,
      [max]: max
    }

    return (
      <div className={style.container}>
        <span className={style.icon}>{icon ? <FontAwesome name={icon} /> : null} {label}</span>
        <div className={style.range}>
          <Slider
            min={min}
            max={max}
            step={this.props.step}
            labels={horizontalLabels}
            handleLabel={this.state.value.toString()}
            value={this.state.value}
            onChange={value => this.setState({ value })} 
            onChangeComplete={this.fireOnChangeComplete}
          />
        </div>
      </div>
    );
  }
}

FilterSlider.defaultProps = {
  icon: null,
  label: '',
  min: null,
  max: null,
  value: null,
  step: 1
}

export default FilterSlider;


