import React, {Component} from 'react';
import style from './OtherOTAPrice.css';
class OtherOTAPrice extends Component {
  render() {
    const {children, price} = this.props;
    return (
      <div className={style.container}>{children} {price ? `€${price}` : null} </div>
    );
  }
}

OtherOTAPrice.defaultProps = {
  price: null
}

export default OtherOTAPrice;


