import React from 'react';
import OfferPayment from './OfferPayment';

class OfferPaymentContainer extends React.Component{

  render = () => {
    const {totalRate, hasFreeCancelation, provider} = this.props.offer.bestOffer;
    const otherOffers = this.props.offer.offers.filter(off => !off.isBest);
    return (<OfferPayment  {...{price: totalRate, hasFreeCancelation, provider, otherOffers}} />)
  }

};

export default OfferPaymentContainer;



