// navigation.js

// Actions
export const FETCH = 'fh/offers/FETCH';
export const FETCHED = 'fh/offers/FETCHED';
export const FETCHING = 'fh/offers/FETCHING';
export const FILTER = 'fh/offers/FILTER';

// Initial State
export const initialState = {
  initialHotels: [],
  hotels: [],
  minPrice: 0,
  maxPrice: 0,
  minRating: 0,
  maxRating: 0
};

// Reducer
export default function reducer(state = initialState, action){
  let {type, data} = action;
  switch(type) {
    case FETCHING :
      return {...state, isFetching: data};
    case FETCHED : 
      return {...state, ...data};
    case FILTER : 
      return {...state, ...{ hotels: filterOffers(data.minRating, data.maxPrice, data.order, state.initialHotels) }  };
    default: 
      return state;
  }
}

// Action creators
export function fetched(data) {
  return {type: FETCHED, data};
}

export function fetchingStatus(data) {
  return {type: FETCHING, data};
}

export function filter(minRating, maxPrice, order) {
  return {type: FILTER, data: {minRating, maxPrice, order}};
}

export const isFetching = () => fetchingStatus(true);
export const notFetching = () => fetchingStatus(false);

export const getOffers = () => {
  return function(dispatch){
    dispatch(isFetching());
    return fetch('fe-challenge.json')
      .then(response => response.json()
      .then(data => {
        dispatch(notFetching());
        dispatch(fetched(decorateOffers(data)));
    }));
  }
}


// Helper Functions 

// Gets filter params, order type and a collection to return a filtered, ordered collection
export const filterOffers = (minPrice, maxRating, order, collection) => {
  const runner = filterRunner(minPrice, maxRating);
  let filteredCollection = runner(collection).run();
  return orderFunctionFactory(order)(filteredCollection);
}

// Returns a curried function that filters a collection
const filterRunner = (minRating, maxPrice) => (collection) => {
  let filteredCollection = [...collection];
  const filters = [
    {
      key: 'minRating',
      fn: () => {
        filteredCollection = filteredCollection.filter(item => item.guestVote > minRating)
      }
    },
    {
      key: 'maxPrice',
      fn: () => {
        filteredCollection = filteredCollection.filter(item => item.bestOffer.totalRate < maxPrice)
      }
    }
  ];

  return {
    run: () => {
      filters.map((filter) => filter.fn())
      return filteredCollection;
    }
  }
}

// Returns a function suited to the specific orderType to order the collection
const orderFunctionFactory = (orderType) => {
  const formulas = {
    starRating: (collection) => {
      return collection.sort((a, b) => {
        return a.starRating < b.starRating
      })
    },
    guestVote: (collection) => {
      return collection.sort((a, b) => {
        return a.guestVote < b.guestVote
      })
    }
  }
  return formulas[orderType] ? formulas[orderType] : (collection) => collection;
}

// Parse and decorate the json to reduce the data manipulation on the views
export const decorateOffers = (data) => {
  data = storeAmenitiesInHotels(data);
  data = storeBestPriceInHotels(data);
  const offers = getAllOffersFromHotels(data);
  const priceDelta = getPriceDeltaFromOffers(offers);
  const ratingDelta = getRatingDeltaFromHotels(data);

  return {
    hotels: data,
    initialHotels: data,
    minPrice: priceDelta[0],
    maxPrice: priceDelta[1],
    minRating: ratingDelta[0],
    maxRating: ratingDelta[1]
  }
}

// Return all offers from a collection of hotels
const getAllOffersFromHotels = (hotels) => {
  return hotels.map(getOffersFromHotel).reduce((offers, pv) => offers.concat(pv), []);
}

// Return all offers from a given hotel
const getOffersFromHotel = (hotel) => {
  return hotel.offers;
}

// Return all ammenities from a collection
const getOfferAmmenities = (offer) => {
  return offer.inclusions;
}

// Gets the max and min price from a collection of offers
const getPriceDeltaFromOffers = (offers: []) => {
  return getDelta(offers, "totalRate");
}

// Gets the max and min rating from a collection of hotels
const getRatingDeltaFromHotels = (hotels: []) => {
  return getDelta(hotels, "guestVote");
}

// Gets the ammenities form a given hotel avoiding dupes
const getAllAmmenitiesFromHotel = (hotel) => {
  return Array.from(
    getOffersFromHotel(hotel)
    .map(getOfferAmmenities)
    .reduce((ammenities, pv) => ammenities.concat(pv), [])
    //Remove duplicates
    .reduce((acc, pv) => {
      acc.add(pv);
      return acc
    }, new Set())
  )
}

// mutate the hotel object to comport a ammenities prop
const storeAmenitiesInHotels = (hotels) => {
  return hotels.map((hotel) => {
    hotel.ammenities = getAllAmmenitiesFromHotel(hotel);
    return hotel;
  })
}

// mutate the hotel object to comport a bestPrice object
const storeBestPriceInHotels = (hotels) => {
  hotels.forEach((hotel) => {
    let bestOffer = hotel.offers.find((offer) => offer.isBest)
    hotel.bestOffer = bestOffer;
  })

  return [...hotels];
}

// Gets the max and min of a given collection using field as finding prop
const getDelta = (collection, field) => {
  const allValues = collection.map((item) => item[field]);
  return [Math.min(...allValues), Math.max(...allValues)];
}



