import React, {Component} from 'react';
import style from './HotelDirectionLink.css';
import FontAwesome  from 'react-fontawesome';

class HotelDirectionLink extends Component {
  render() {
    const {children} = this.props;
    return (
      <div className={style.container}><FontAwesome name='location-arrow' /> {children}</div>
    );
  }
}

export default HotelDirectionLink;


