import React from 'react';
import OfferImage from './OfferImage';
const GREAT_OFFER_TRESHOLD = 8.5;

class OfferImageContainer extends React.Component{

  constructor(props){
    super(props);
    const {offer} = props;
    this.state = {
      image: ((offer.images && offer.images.length > 0) ? offer.images[0].small : null),
      isGreatOffer: offer.guestVote > GREAT_OFFER_TRESHOLD
    }
  }

  componentWillReceiveProps(next) {
    const {offer} = next;
    this.setState({
      image: ((offer.images && offer.images.length > 0) ? offer.images[0].small : null),
      isGreatOffer: offer.guestVote > GREAT_OFFER_TRESHOLD
    })
  }

  render = () => (<OfferImage {...this.state} />)
};

export default OfferImageContainer;


