import React, {Component} from 'react';
import style from './SmileRating.css';
import FontAwesome  from 'react-fontawesome';
class SmileRating extends Component {

  MAX_VOTE = 10;
  votes = [
    'Fabulous',
    'Fabulous',
    'Very Good',
    'Good',
    'Pleasant'
  ];

  voteLabel = '';
  
  render() {
    this.voteLabel = this.votes[ Math.min( Math.floor( this.MAX_VOTE - this.props.vote), this.votes.length-1 ) ];
    return (
      <div className={style.container}>
        <FontAwesome name='smile-o' />
        <span className={style.label}>{this.props.vote} - {this.voteLabel}</span>
      </div>
    );
  }
}

SmileRating.defaultProps = {
  vote: 0
}

export default SmileRating;


