import React, {Component} from 'react';
import style from './OfferImage.css';
import Ribbon from 'sharedComponents/Ribbon';
import Heart from 'sharedComponents/Heart';

class OfferImage extends Component {
  
  render() {
    const {image, isGreatOffer} = this.props;
    return (
      <div className={style.container}>
        {isGreatOffer ? <div className={style.ribbon}><Ribbon>GREAT OFFER</Ribbon></div> : null }
        <div className={style.heart}><Heart /></div>
        {image ? <img src={image} width="250" alt=""/> : null }
      </div>
    );
  }
}

export default OfferImage;


