import React, {Component} from 'react';
import style from './StarRating.css';
import FontAwesome  from 'react-fontawesome';
class StarRating extends Component {

  normalizedRating = 0;
  totalStars = 5;

  renderStars = (rating) => {
    this.normalizedRating = Math.floor(rating);
    let stars = [];
    for (let index = 0; index < this.totalStars; index++) {
      stars.push( (index < this.normalizedRating) ? <FontAwesome key={index} name='star' /> : <FontAwesome key={index} name='star-o' />)
    }
    return stars;
  }

  render() {
    return (
      <div className={style.container}>
        {this.renderStars(this.props.rating)}
      </div>
    );
  }
}

StarRating.defaultProps = {
  rating: 0
}

export default StarRating;


