import React, {Component} from 'react';
import style from './OfferInformation.css';

import StarRating from 'sharedComponents/StarRating';
import HotelDirectionLink from 'sharedComponents/HotelDirectionLink';
import SmileRating from 'sharedComponents/SmileRating';
import Pill from 'sharedComponents/Pill';

class OfferInformation extends Component {

  render() {
    const {name, starRating, placeShort, guestVote, ammenities} = this.props;

    return (
      <div className={style.container}>
        <h3 className={style.hotelName}>{name}</h3>
        <div className={style.starRating}><StarRating rating={starRating} /></div>
        <div className={style.hotelDirection}><HotelDirectionLink>{placeShort}</HotelDirectionLink></div>
        <div className={style.smileRating}><SmileRating vote={guestVote}></SmileRating></div>
        <div className={style.pill}>
          {ammenities.map((amm, idx) => <Pill key={idx}>{amm}</Pill>)}
        </div>
      </div>
    );
  }
}

OfferInformation.defaultProps = {
  ammenities: [],
  name: '',
  starRating: 0,
  placeShort: '',
  guestVote: 0 
}

export default OfferInformation;


