import React, {Component} from 'react';
import MainLayout from 'core/MainLayout';
import Offer from 'pageComponents/offers/Offer';
import FilterSlider from 'sharedComponents/FilterSlider';

import style from './Offers.css';
class Offers extends Component {

  filters = {
    minRating: 0,
    maxPrice: 9999
  }

  order: '';

  componentDidMount(){
    this.props.getOffers();
  }

  runFilter(field){
    return (value) => {
      this.filters[field] = value;
      this.props.filter(this.filters.minRating, this.filters.maxPrice);
    }
  }

  handleOrdering = (evt) => {
    this.setState({order: evt.target.value})
    this.props.filter(this.filters.minRating, this.filters.maxPrice, evt.target.value);
  }

  render() {
    return (
      <MainLayout> 
        <div className={style.filters}>
          <div><FilterSlider value={this.filters.maxPrice} onChangeComplete={this.runFilter('maxPrice')} min={this.props.offers.minPrice} max={this.props.offers.maxPrice} label='Max price' icon='eur' /></div>
          <div><FilterSlider step={0.5} value={this.filters.minRating} onChangeComplete={this.runFilter('minRating')} min={this.props.offers.minRating} max={this.props.offers.maxRating} label='Min rating' icon='smile-o' /></div>
        </div>
        
        <span className={style.found}>Order by: </span>
        <select value={this.order} className={style.order} onChange={this.handleOrdering}>
          <option value="">Recommended</option>
          <option value="starRating">Stars</option>
          <option value="guestVote">Guest Vote</option>
        </select>

        <span className={style.found}>We found {this.props.offers.hotels.length} hotels</span>

        <div className={style.offers}>
          {this.props.offers.hotels.map((offer, idx) => (<div key={idx} className={style.offer}><Offer offer={offer}></Offer></div>))}
        </div>

      </MainLayout>
    );
  }
}

Offers.defaultProps = {
  getOffers: () => [],
  offers: { hotels: [] }
}

export default Offers;


