import React, {Component} from 'react';
import style from './Offer.css';
import OfferImage from 'pageComponents/offers/OfferImage/OfferImageContainer';
import OfferInformation from 'pageComponents/offers/OfferInformation/OfferInformationContainer';
import OfferPayment from 'pageComponents/offers/OfferPayment/OfferPaymentContainer';
class Offer extends Component {

  render() {
    const {offer} = this.props;
    return (
      <div className={style.container}>
        <div className={style.offerimage}><OfferImage offer={offer} /></div>
        <div className={style.offerinformation}><OfferInformation offer={this.props.offer} /></div>
        <div className={style.offerpayment}><OfferPayment offer={offer} /></div>
      </div>
    );
  }
}

export default Offer;


