import React, {Component} from 'react';
import style from './OfferPayment.css';

import Price from 'sharedComponents/Price';
import OtherOTAPrice from 'sharedComponents/OtherOTAPrice';
import PrimaryButton from 'sharedComponents/PrimaryButton';
import CancelationPolicy from 'pageComponents/offers/CancelationPolicy';

class OfferPayment extends Component {
  render() {
    const {price, hasFreeCancelation, provider, otherOffers} = this.props;
    return (
      <div className={style.container}>
        <div><Price>{price}</Price></div>
        {hasFreeCancelation?<div><CancelationPolicy>Free cancelation</CancelationPolicy></div>:null}
        <div><PrimaryButton>{provider.name}</PrimaryButton></div>
        {otherOffers.map((offer, ind) => <div key={ind}><OtherOTAPrice price={offer.totalRate}>{offer.provider.name}</OtherOTAPrice></div>)}
      </div>
    );
  }
}

export default OfferPayment;


